revision.text:
/* {{pp-template}} */
.mw-tmpl-kbd {
	background: #EEE;
	color: var(--color-base);
}

html.skin-theme-clientpref-night .mw-tmpl-kbd {
	background: #171a1d;
}

@media ( prefers-color-scheme: dark ) {
	html.skin-theme-clientpref-os .mw-tmpl-kbd {
		background: #171a1d;
	}
}

